144	/**
145	 * Returns the object with properties sorted by property name.
146	 * @template {object} T
147	 * @param {T} obj an object
148	 * @param {(keyof T)[]} keys the keys of the object
149	 * @returns {T} the object with properties sorted by property name
150	 */
151	const sortObject = (obj, keys) => {
152		const o = /** @type {T} */ ({});
153		for (const k of keys.sort()) {
154			o[k] = obj[k];
155		}
156		return o;
157	};
