497		/**
498		 * Release fields on a finished compilation that nothing reads after emit,
499		 * so the heap can shrink while user code still holds the Stats reference.
500		 * Recurses into child compilations. Stats output is preserved — only
501		 * codeGen byproducts are dropped.
502		 * @param {Compilation} compilation finished compilation to slim down
503		 * @returns {void}
504		 */
505		_releaseUnusedCompilationData(compilation) {
506			for (const child of compilation.children) {
507				this._releaseUnusedCompilationData(child);
508			}
509			// Rendered source per (module × runtime) — used only during seal/emit,
510			// never read by Stats, and not serialized to the persistent cache.
511			if (compilation.codeGenerationResults !== undefined) {
512				compilation.codeGenerationResults.map.clear();
513			}
514		}
515	
516		/**
517		 * Returns a compiler watcher.
518		 * @param {WatchOptions} watchOptions the watcher's options
519		 * @param {Callback<Stats>} handler signals when the call finishes
520		 * @returns {Watching | undefined} a compiler watcher
521		 */
522		watch(watchOptions, handler) {
523			if (this.running) {
524				handler(new ConcurrentCompilationError());
525				return;
526			}
527	
528			this.running = true;
529			this.watchMode = true;
530			this.watching = new Watching(this, watchOptions, handler);
531			return this.watching;
532		}
533	
534		/**
535		 * Processes the provided stat.
536		 * @param {Callback<Stats>} callback signals when the call finishes
537		 * @returns {void}
538		 */
539		run(callback) {
540			if (this.running) {
541				callback(new ConcurrentCompilationError());
542				return;
543			}
544	
545			/** @type {Logger | undefined} */
546			let logger;
547	
548			/**
549			 * Processes the provided err.
550			 * @param {Error | null} err error
551			 * @param {Stats=} stats stats
552			 */
553			const finalCallback = (err, stats) => {
554				if (logger) logger.time("beginIdle");
555				this.idle = true;
556				this.cache.beginIdle();
557				if (logger) logger.timeEnd("beginIdle");
558				this.running = false;
559				if (err) {
560					this.hooks.failed.call(err);
561				}
562				if (callback !== undefined) callback(err, stats);
563				this.hooks.afterDone.call(/** @type {Stats} */ (stats));
564			};
565	
566			const startTime = Date.now();
567	
568			this.running = true;
569	
570			/**
571			 * Processes the provided err.
572			 * @param {Error | null} err error
573			 * @param {Compilation=} _compilation compilation
574			 * @returns {void}
575			 */
576			const onCompiled = (err, _compilation) => {
577				if (err) return finalCallback(err);
578	
579				const compilation = /** @type {Compilation} */ (_compilation);
580	
581				if (this.hooks.shouldEmit.call(compilation) === false) {
582					compilation.startTime = startTime;
583					compilation.endTime = Date.now();
584					const stats = new Stats(compilation);
585					this.hooks.done.callAsync(stats, (err) => {
586						if (err) return finalCallback(err);
587						return finalCallback(null, stats);
588					});
589					return;
590				}
591	
592				process.nextTick(() => {
593					logger = compilation.getLogger("webpack.Compiler");
594					logger.time("emitAssets");
595					this.emitAssets(compilation, (err) => {
596						/** @type {Logger} */
597						(logger).timeEnd("emitAssets");
598						if (err) return finalCallback(err);
599	
600						if (compilation.hooks.needAdditionalPass.call()) {
601							compilation.needAdditionalPass = true;
602	
603							compilation.startTime = startTime;
604							compilation.endTime = Date.now();
605							/** @type {Logger} */
606							(logger).time("done hook");
607							const stats = new Stats(compilation);
608							this.hooks.done.callAsync(stats, (err) => {
609								/** @type {Logger} */
610								(logger).timeEnd("done hook");
611								if (err) return finalCallback(err);
612	
613								this.hooks.additionalPass.callAsync((err) => {
614									if (err) return finalCallback(err);
615									this.compile(onCompiled);
616								});
617							});
618							return;
619						}
620	
621						/** @type {Logger} */
622						(logger).time("emitRecords");
623						this.emitRecords((err) => {
624							/** @type {Logger} */
625							(logger).timeEnd("emitRecords");
626							if (err) return finalCallback(err);
627	
628							compilation.startTime = startTime;
629							compilation.endTime = Date.now();
630							/** @type {Logger} */
631							(logger).time("done hook");
