118					if (doneCompilers === this.compilers.length) {
119						this.hooks.done.call(
120							new MultiStats(/** @type {Stats[]} */ (compilerStats))
121						);
122					}
123				});
124				// eslint-disable-next-line no-loop-func
125				compiler.hooks.invalid.tap(CLASS_NAME, () => {
126					if (compilerDone) {
127						compilerDone = false;
128						doneCompilers--;
129					}
130				});
131				// Release fields on this child's Compilation once it's done. The
132				// stage: Infinity tap runs after every afterDone tap at a lower
133				// stage, so plugins observing compilation state in afterDone still
134				// see it intact. Stats remains usable; only fields Stats never reads
135				// (and that the persistent cache never serializes) are dropped.
136	
137				compiler.hooks.afterDone.tap(
138					{ name: CLASS_NAME, stage: Infinity },
139					(stats) => {
140						if (stats !== undefined) {
141							compiler._releaseUnusedCompilationData(stats.compilation);
142						}
143					}
144				);
145			}
146			this._validateCompilersOptions();
147		}
