149		_validateCompilersOptions() {
150			if (this.compilers.length < 2) return;
151			/**
152			 * Adds the provided compiler to the multi compiler.
153			 * @param {Compiler} compiler compiler
154			 * @param {WebpackError} warning warning
155			 */
156			const addWarning = (compiler, warning) => {
157				compiler.hooks.thisCompilation.tap(CLASS_NAME, (compilation) => {
158					compilation.warnings.push(warning);
159				});
160			};
161			/** @type {Set<string>} */
162			const cacheNames = new Set();
163			for (const compiler of this.compilers) {
164				if (compiler.options.cache && "name" in compiler.options.cache) {
165					const name = /** @type {string} */ (compiler.options.cache.name);
166					if (cacheNames.has(name)) {
167						addWarning(
168							compiler,
169							new WebpackError(
170								`${
171									compiler.name
172										? `Compiler with name "${compiler.name}" doesn't use unique cache name. `
173										: ""
174								}Please set unique "cache.name" option. Name "${name}" already used.`
175							)
176						);
177					} else {
178						cacheNames.add(name);
179					}
180				}
181			}
182		}
