281		/**
282		 * Validate dependencies.
283		 * @param {Callback<MultiStats>} callback signals when the validation is complete
284		 * @returns {boolean} true if the dependencies are valid
285		 */
286		validateDependencies(callback) {
287			/** @type {Set<{ source: Compiler, target: Compiler }>} */
288			const edges = new Set();
289			/** @type {string[]} */
290			const missing = [];
291			/**
292			 * Returns target was found.
293			 * @param {Compiler} compiler compiler
294			 * @returns {boolean} target was found
295			 */
296			const targetFound = (compiler) => {
297				for (const edge of edges) {
298					if (edge.target === compiler) {
299						return true;
300					}
301				}
302				return false;
303			};
304			/**
305			 * Returns result.
306			 * @param {{ source: Compiler, target: Compiler }} e1 edge 1
307			 * @param {{ source: Compiler, target: Compiler }} e2 edge 2
308			 * @returns {number} result
309			 */
310			const sortEdges = (e1, e2) =>
311				/** @type {string} */
312				(e1.source.name).localeCompare(/** @type {string} */ (e2.source.name)) ||
313				/** @type {string} */
314				(e1.target.name).localeCompare(/** @type {string} */ (e2.target.name));
315			for (const source of this.compilers) {
316				const dependencies = this.dependencies.get(source);
317				if (dependencies) {
318					for (const dep of dependencies) {
319						const target = this.compilers.find((c) => c.name === dep);
320						if (!target) {
321							missing.push(dep);
322						} else {
323							edges.add({
324								source,
325								target
326							});
327						}
328					}
329				}
330			}
331			/** @type {string[]} */
332			const errors = missing.map(
333				(m) => `Compiler dependency \`${m}\` not found.`
334			);
335			const stack = this.compilers.filter((c) => !targetFound(c));
336			while (stack.length > 0) {
337				const current = stack.pop();
338				for (const edge of edges) {
339					if (edge.source === current) {
340						edges.delete(edge);
341						const target = edge.target;
342						if (!targetFound(target)) {
343							stack.push(target);
344						}
345					}
346				}
347			}
348			if (edges.size > 0) {
349				/** @type {string[]} */
350				const lines = [...edges]
351					.sort(sortEdges)
352					.map((edge) => `${edge.source.name} -> ${edge.target.name}`);
353				lines.unshift("Circular dependency found in compiler dependencies.");
354				errors.unshift(lines.join("\n"));
355			}
356			if (errors.length > 0) {
357				const message = errors.join("\n");
358				callback(new Error(message));
359				return false;
360			}
361			return true;
362		}
