364		// TODO webpack 6 remove
365		/**
366		 * Run with dependencies.
367		 * @deprecated This method should have been private
368		 * @param {Compiler[]} compilers the child compilers
369		 * @param {RunWithDependenciesHandler} fn a handler to run for each compiler
370		 * @param {Callback<Stats[]>} callback the compiler's handler
371		 * @returns {void}
372		 */
373		runWithDependencies(compilers, fn, callback) {
374			/** @type {Set<string>} */
375			const fulfilledNames = new Set();
376			let remainingCompilers = compilers;
377			/**
378			 * Checks whether this multi compiler is dependency fulfilled.
379			 * @param {string} d dependency
380			 * @returns {boolean} when dependency was fulfilled
381			 */
382			const isDependencyFulfilled = (d) => fulfilledNames.has(d);
383			/**
384			 * Gets ready compilers.
385			 * @returns {Compiler[]} compilers
386			 */
387			const getReadyCompilers = () => {
388				/** @type {Compiler[]} */
389				const readyCompilers = [];
390				const list = remainingCompilers;
391				remainingCompilers = [];
392				for (const c of list) {
393					const dependencies = this.dependencies.get(c);
394					const ready =
395						!dependencies || dependencies.every(isDependencyFulfilled);
396					if (ready) {
397						readyCompilers.push(c);
398					} else {
399						remainingCompilers.push(c);
400					}
401				}
402				return readyCompilers;
403			};
404			/**
405			 * Processes the provided stat.
406			 * @param {Callback<Stats[]>} callback callback
407			 * @returns {void}
408			 */
409			const runCompilers = (callback) => {
410				if (remainingCompilers.length === 0) return callback(null);
411				asyncLib.map(
412					getReadyCompilers(),
413					(compiler, callback) => {
414						fn(compiler, (err) => {
415							if (err) return callback(err);
416							fulfilledNames.add(/** @type {string} */ (compiler.name));
417							runCompilers(callback);
418						});
419					},
420					(err, results) => {
421						callback(/** @type {Error | null} */ (err), results);
422					}
423				);
424			};
425			runCompilers(callback);
426		}
427	
428		/**
429		 * Returns result of setup.
430		 * @template SetupResult
431		 * @param {(compiler: Compiler, index: number, doneCallback: Callback<Stats>, isBlocked: () => boolean, setChanged: () => void, setInvalid: () => void) => SetupResult} setup setup a single compiler
432		 * @param {(compiler: Compiler, setupResult: SetupResult, callback: Callback<Stats>) => void} run run/continue a single compiler
433		 * @param {Callback<MultiStats>} callback callback when all compilers are done, result includes Stats of all changed compilers
434		 * @returns {SetupResult[]} result of setup
435		 */
436		_runGraph(setup, run, callback) {
437			/** @typedef {{ compiler: Compiler, setupResult: undefined | SetupResult, result: undefined | Stats, state: "pending" | "blocked" | "queued" | "starting" | "running" | "running-outdated" | "done", children: Node[], parents: Node[] }} Node */
438	
439			// State transitions for nodes:
440			// -> blocked (initial)
441			// blocked -> starting [running++] (when all parents done)
442			// queued -> starting [running++] (when processing the queue)
443			// starting -> running (when run has been called)
444			// running -> done [running--] (when compilation is done)
445			// done -> pending (when invalidated from file change)
446			// pending -> blocked [add to queue] (when invalidated from aggregated changes)
447			// done -> blocked [add to queue] (when invalidated, from parent invalidation)
448			// running -> running-outdated (when invalidated, either from change or parent invalidation)
449			// running-outdated -> blocked [running--] (when compilation is done)
450	
451			/** @type {Node[]} */
452			const nodes = this.compilers.map((compiler) => ({
453				compiler,
454				setupResult: undefined,
455				result: undefined,
456				state: "blocked",
457				children: [],
458				parents: []
459			}));
460			/** @type {Map<string, Node>} */
461			const compilerToNode = new Map();
462			for (const node of nodes) {
463				compilerToNode.set(/** @type {string} */ (node.compiler.name), node);
464			}
465			for (const node of nodes) {
466				const dependencies = this.dependencies.get(node.compiler);
467				if (!dependencies) continue;
468				for (const dep of dependencies) {
469					const parent = /** @type {Node} */ (compilerToNode.get(dep));
470					node.parents.push(parent);
471					parent.children.push(node);
472				}
473			}
474			/** @type {ArrayQueue<Node>} */
475			const queue = new ArrayQueue();
476			for (const node of nodes) {
477				if (node.parents.length === 0) {
478					node.state = "queued";
479					queue.enqueue(node);
480				}
481			}
482			let errored = false;
483			let running = 0;
484			const parallelism = /** @type {number} */ (this._options.parallelism);
485			/**
486			 * Processes the provided node.
487			 * @param {Node} node node
488			 * @param {(Error | null)=} err error
489			 * @param {Stats=} stats result
490			 * @returns {void}
491			 */
492			const nodeDone = (node, err, stats) => {
493				if (errored) return;
494				if (err) {
495					errored = true;
496					return asyncLib.each(
497						nodes,
498						(node, callback) => {
499							if (node.compiler.watching) {
500								node.compiler.watching.close(callback);
501							} else {
502								callback();
503							}
504						},
505						() => callback(err)
506					);
507				}
508				node.result = stats;
509				running--;
510				if (node.state === "running") {
511					node.state = "done";
512					for (const child of node.children) {
513						if (child.state === "blocked") queue.enqueue(child);
514					}
515				} else if (node.state === "running-outdated") {
516					node.state = "blocked";
517					queue.enqueue(node);
518				}
519				processQueue();
520			};
521			/**
522			 * Node invalid from parent.
523			 * @param {Node} node node
524			 * @returns {void}
525			 */
526			const nodeInvalidFromParent = (node) => {
527				if (node.state === "done") {
528					node.state = "blocked";
529				} else if (node.state === "running") {
530					node.state = "running-outdated";
531				}
532				for (const child of node.children) {
533					nodeInvalidFromParent(child);
534				}
535			};
536			/**
537			 * Processes the provided node.
538			 * @param {Node} node node
539			 * @returns {void}
540			 */
541			const nodeInvalid = (node) => {
542				if (node.state === "done") {
543					node.state = "pending";
544				} else if (node.state === "running") {
545					node.state = "running-outdated";
546				}
547				for (const child of node.children) {
548					nodeInvalidFromParent(child);
549				}
550			};
551			/**
552			 * Processes the provided node.
553			 * @param {Node} node node
554			 * @returns {void}
555			 */
556			const nodeChange = (node) => {
557				nodeInvalid(node);
558				if (node.state === "pending") {
559					node.state = "blocked";
560				}
561				if (node.state === "blocked") {
562					queue.enqueue(node);
563					processQueue();
564				}
565			};
566	
567			/** @type {SetupResult[]} */
568			const setupResults = [];
569			for (const [i, node] of nodes.entries()) {
570				setupResults.push(
571					(node.setupResult = setup(
572						node.compiler,
573						i,
574						nodeDone.bind(null, node),
575						() => node.state !== "starting" && node.state !== "running",
576						() => nodeChange(node),
577						() => nodeInvalid(node)
578					))
579				);
580			}
581			let processing = true;
582			const processQueue = () => {
583				if (processing) return;
584				processing = true;
585				process.nextTick(processQueueWorker);
586			};
587			const processQueueWorker = () => {
588				// eslint-disable-next-line no-unmodified-loop-condition
589				while (running < parallelism && queue.length > 0 && !errored) {
590					const node = /** @type {Node} */ (queue.dequeue());
591					if (
592						node.state === "queued" ||
593						(node.state === "blocked" &&
594							node.parents.every((p) => p.state === "done"))
595					) {
596						running++;
597						node.state = "starting";
598						run(
599							node.compiler,
600							/** @type {SetupResult} */ (node.setupResult),
601							nodeDone.bind(null, node)
602						);
603						node.state = "running";
604					}
605				}
606				processing = false;
607				if (
608					!errored &&
609					running === 0 &&
610					nodes.every((node) => node.state === "done")
611				) {
612					/** @type {Stats[]} */
613					const stats = [];
614					for (const node of nodes) {
615						const result = node.result;
616						if (result) {
617							node.result = undefined;
618							stats.push(result);
619						}
620					}
621					if (stats.length > 0) {
622						callback(null, new MultiStats(stats));
623					}
624				}
625			};
626			processQueueWorker();
627			return setupResults;
628		}
