630		/**
631		 * Returns a compiler watcher.
632		 * @param {WatchOptions | WatchOptions[]} watchOptions the watcher's options
633		 * @param {Callback<MultiStats>} handler signals when the call finishes
634		 * @returns {MultiWatching | undefined} a compiler watcher
635		 */
636		watch(watchOptions, handler) {
637			if (this.running) {
638				handler(new ConcurrentCompilationError());
639				return;
640			}
641			this.running = true;
642	
643			if (this.validateDependencies(handler)) {
644				const watchings = this._runGraph(
645					(compiler, idx, callback, isBlocked, setChanged, setInvalid) => {
646						const watching = compiler.watch(
647							Array.isArray(watchOptions) ? watchOptions[idx] : watchOptions,
648							callback
649						);
650						if (watching) {
651							watching._onInvalid = setInvalid;
652							watching._onChange = setChanged;
653							watching._isBlocked = isBlocked;
654						}
655						return watching;
656					},
657					(compiler, watching, _callback) => {
658						if (compiler.watching !== watching) return;
659						if (!watching.running) watching.invalidate();
660					},
661					handler
662				);
663				return new MultiWatching(watchings, this);
664			}
665	
666			return new MultiWatching([], this);
667		}
668	
669		/**
670		 * Processes the provided multi stat.
671		 * @param {Callback<MultiStats>} callback signals when the call finishes
672		 * @returns {void}
673		 */
674		run(callback) {
675			if (this.running) {
676				callback(new ConcurrentCompilationError());
677				return;
678			}
679			this.running = true;
680	
681			if (this.validateDependencies(callback)) {
682				this._runGraph(
683					() => {},
684					(compiler, setupResult, callback) => compiler.run(callback),
685					(err, stats) => {
686						this.running = false;
687	
688						if (callback !== undefined) {
689							return callback(err, stats);
690						}
691					}
692				);
693			}
694		}
695	
696		purgeInputFileSystem() {
697			for (const compiler of this.compilers) {
698				if (compiler.inputFileSystem && compiler.inputFileSystem.purge) {
699					compiler.inputFileSystem.purge();
700				}
701			}
702		}
703	
704		/**
705		 * Processes the provided error callback.
706		 * @param {ErrorCallback} callback signals when the compiler closes
707		 * @returns {void}
708		 */
709		close(callback) {
710			asyncLib.each(
711				this.compilers,
712				(compiler, callback) => {
713					compiler.close(callback);
714				},
715				(error) => {
716					callback(/** @type {Error | null} */ (error));
717				}
718			);
719		}
720	};
