308					this._go();
309				}
310				return;
311			}
312	
313			if (compilation) {
314				compilation.startTime = /** @type {number} */ (this.startTime);
315				compilation.endTime = Date.now();
316				stats = new Stats(compilation);
317			}
318			this.startTime = null;
319			if (err) return handleError(err);
